import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { Link } from "react-router-dom";
import { toast } from "react-toastify";

function Home() {
  const user = useSelector((state) => state.auth.user);
  const [announcements, setAnnouncements] = useState([]);
  const [notifications, setNotifications] = useState([]);

  useEffect(() => {
    // Загрузка объявлений только для авторизованных пользователей
    if (user?.id) {
      fetch("http://localhost:3001/announcements")
        .then((res) => res.json())
        .then((data) => setAnnouncements(data))
        .catch((error) => toast.error("Ошибка загрузки объявлений"));

      // Загрузка уведомлений
      fetch(`http://localhost:3001/notifications?userId=${user.id}`)
        .then((res) => res.json())
        .then((data) => setNotifications(data))
        .catch((error) => toast.error("Ошибка загрузки уведомлений"));
    }
  }, [user]);

  return (
    <div className="home-container">
      <div className="container mt-5">
        <h1 className="mb-4 text-white text-center">Добро пожаловать!</h1>

        {/* Приветственное сообщение */}
        <div className="card shadow-lg mb-4 home-card">
          <div className="card-body text-center">
            {user ? (
              <>
                <h2 className="mb-3">Привет, {user.name}!</h2>
                <p className="text-muted">
                  Ты {user.role === "student" ? "студент" : user.role === "teacher" ? "учитель" : "администратор"}.
                  Начни работу с платформой!
                </p>
                <div className="d-flex flex-wrap justify-content-center gap-2">
                  <Link to="/dashboard" className="btn btn-primary btn-lg home-btn">
                    <i className="bi bi-person-circle me-2"></i>Личный кабинет
                  </Link>
                  <Link to="/courses" className="btn btn-primary btn-lg home-btn">
                    <i className="bi bi-book me-2"></i>
                    {user.role === "teacher" ? "Мои курсы" : "Курсы"}
                  </Link>
                  {user.role === "admin" && (
                    <Link to="/admin" className="btn btn-primary btn-lg home-btn">
                      <i className="bi bi-gear me-2"></i>Админ-панель
                    </Link>
                  )}
                  {user.role === "student" && (
                    <Link to="/enrollments" className="btn btn-primary btn-lg home-btn">
                      <i className="bi bi-list-check me-2"></i>Мои записи
                    </Link>
                  )}
                </div>
              </>
            ) : (
              <>
                <h2 className="mb-3">Начни учиться!</h2>
                <p className="text-muted">
                  Войди или зарегистрируйся, чтобы открыть мир знаний.
                </p>
                <div className="d-flex flex-wrap justify-content-center gap-2">
                  <Link to="/login" className="btn btn-primary btn-lg home-btn">
                    <i className="bi bi-box-arrow-in-right me-2"></i>Войти
                  </Link>
                  <Link to="/register" className="btn btn-outline-light btn-lg home-btn">
                    <i className="bi bi-person-plus me-2"></i>Регистрация
                  </Link>
                </div>
              </>
            )}
          </div>
        </div>

        {/* Объявления и уведомления только для авторизованных пользователей */}
        {user && (
          <>
            {/* Последние объявления */}
            <div className="card shadow-lg mb-4 home-card">
              <div className="card-body">
                <h2 className="mb-3">
                  <i className="bi bi-megaphone me-2"></i>Объявления
                </h2>
                {announcements.length === 0 ? (
                  <p className="text-muted">Объявлений нет</p>
                ) : (
                  <ul className="list-group list-group-flush">
                    {announcements.slice(0, 3).map((announcement) => (
                      <li
                        key={announcement.id}
                        className="list-group-item home-list-item"
                      >
                        <strong>{announcement.title}</strong>
                        <p className="mb-1">{announcement.message}</p>
                        <small className="text-muted">
                          {new Date(announcement.createdAt).toLocaleString()}
                        </small>
                      </li>
                    ))}
                  </ul>
                )}
              </div>
            </div>

            {/* Уведомления */}
            <div className="card shadow-lg mb-4 home-card">
              <div className="card-body">
                <h2 className="mb-3">
                  <i className="bi bi-bell me-2"></i>Уведомления
                </h2>
                {notifications.length === 0 ? (
                  <p className="text-muted">Уведомлений нет</p>
                ) : (
                  <ul className="list-group list-group-flush">
                    {notifications.slice(0, 3).map((notification) => (
                      <li
                        key={notification.id}
                        className="list-group-item home-list-item"
                      >
                        {notification.message}
                        <br />
                        <small className="text-muted">
                          {new Date(notification.createdAt).toLocaleString()}
                        </small>
                      </li>
                    ))}
                  </ul>
                )}
              </div>
            </div>
          </>
        )}
      </div>

      <style jsx>{`
        .home-container {
          background: linear-gradient(135deg, #1e3a8a 0%, #3b82f6 100%);
          min-height: 100vh;
          padding-bottom: 2rem;
        }
        .home-card {
          border: none;
          border-radius: 15px;
          background: rgba(255, 255, 255, 0.95);
          transition: transform 0.3s ease, box-shadow 0.3s ease;
        }
        .home-card:hover {
          transform: translateY(-5px);
          box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);
        }
        .home-btn {
          border-radius: 10px;
          padding: 0.75rem 1.5rem;
          transition: background-color 0.3s ease, transform 0.2s ease;
        }
        .home-btn:hover {
          transform: scale(1.05);
        }
        .home-list-item {
          border: none;
          border-radius: 10px;
          margin-bottom: 0.5rem;
          background: rgba(255, 255, 255, 0.1);
          transition: background 0.3s ease;
        }
        .home-list-item:hover {
          background: rgba(255, 255, 255, 0.2);
        }
        @media (max-width: 576px) {
          .home-btn {
            width: 100%;
            margin-bottom: 0.5rem;
          }
          .home-card {
            margin-bottom: 1.5rem;
          }
        }
      `}</style>
    </div>
  );
}

export default Home;
